code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = i + 1;
            }
            for (int i = 0; i < M; i++) {
                int w = sc.nextInt();
                int x = sc.nextInt();
                int y = sc.nextInt();
                int z = sc.nextInt();
                x--; y--;
                for (int j = x; j <= y; j++) {
                    if (w == 1) {
                        arr[j] += z;
                    } else {
                        arr[j] -= z;
                    }
                }
            }
            int max = Integer.MIN_VALUE, min = Integer.MAX_VALUE;
            for (int i = 0; i < N; i++) {
                max = Math.max(max, arr[i]);
                min = Math.min(min, arr[i]);
            }
            System.out.println(max - min + 1);
        }
    }
}

