const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    let arr = Array(N).fill(0).map((_, i) => i + 1);
    for (let j = 0; j < M; j++) {
        const [w, x, y, z] = readline().split(' ').map(Number);
        x--; y--;
        for (let k = x; k <= y; k++) {
            if (w === 1) {
                arr[k] += z;
            } else {
                arr[k] -= z;
            }
        }
    }
    console.log(Math.max(...arr) - Math.min(...arr) + 1);
}
